sql:
SELECT AVG(teachers_per_student) AS avg_teacher_student_ratio
FROM teacher_metrics
WHERE school_id = 1;

external_knowledge:
- 'Spark in academic vigor' refers to schools where the average number of students with one or more AP exams and the average percentage of students taking the SAT/ACT are both greater than 0; 
- 'AP engagement' refers to students_AP_exam_oneormore; 
- 'College readiness' refers to students_SAT_ACT.
